/**
 * Resolve an icon path for an item, resource, or building.
 * Accepts either an Unreal class name ("Desc_IronOre_C", "Build_SmelterMk1_C")
 * or a kebab slug ("iron-ore", "smelter-mk1"). Returns {@link DEFAULT_ICON} if unknown.
 */
export function getItemIcon(slug: string): string {
  if (!slug) return DEFAULT_ICON;
  const direct = BY_CLASS[slug] ?? BY_SLUG[slug];
  if (direct) return direct;
  // tolerate Build_/Desc_ swaps not pre-mapped
  if (slug.startsWith("Build_")) {
    const d = BY_CLASS["Desc_" + slug.slice(6)];
    if (d) return d;
  } else if (slug.startsWith("Desc_")) {
    const b = BY_CLASS["Build_" + slug.slice(5)];
    if (b) return b;
  }
  return DEFAULT_ICON;
}

/** True if a non-default icon exists for the given class name or slug. */
export function hasItemIcon(slug: string): boolean {
  return getItemIcon(slug) !== DEFAULT_ICON;
}
